import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]); // [axis, coord]
  const [polyPoints, setPolyPoints] = useState([]);
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [showPreview, setShowPreview] = useState(false);

  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  // Fix kích thước ảnh 1920x1080
  const FIXED_WIDTH = 1920;
  const FIXED_HEIGHT = 1080;

  // Format output theo yêu cầu
  const generateOutput = () => {
    // Nếu chưa có dữ liệu, trả về 0
    const axis = lines[0] ? [
      Number((lines[0][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[0][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    const coord = lines[1] ? [
      Number((lines[1][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[1][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    // Zone polygon: nếu có đủ 4 điểm thì lấy, không thì [0,0,0,0,0,0,0,0]
    const zone = polyPoints.length >= 4 ? 
      polyPoints.slice(0, 4).flatMap(p => [
        Number((p.x / FIXED_WIDTH).toFixed(3)),
        Number((p.y / FIXED_HEIGHT).toFixed(3))
      ]) : [0, 0, 0, 0, 0, 0, 0, 0];

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl || "",
            cam_id: generateUUID()
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [{
              ID: generateUUID(),
              type: 1,
              axis: axis,
              coord: coord
            }],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  // Kiểm tra các bước đã config chưa
  const getStepStatus = () => {
    return {
      step1: lines.length >= 1 ? axis : 0,
      step2: lines.length >= 2 ? coord : 0,
      step3: polyPoints.length >= 4 ? polyPoints : 0
    };
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  // Xử lý mouse events
  const handleMouseDown = (e) => {
    if (!canvasRef.current) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    if (currentStep === 3) {
      if (polyPoints.length < 4) {
        const newPoint = { x, y };
        setPolyPoints([...polyPoints, newPoint]);
        redrawAll();
      }
    } else {
      setDrawing(true);
      setIx(x);
      setIy(y);
    }
  };

  const handleMouseMove = (e) => {
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const ctx = canvasRef.current.getContext('2d');

    requestAnimationFrame(() => {
      redrawAll();

      ctx.beginPath();
      ctx.moveTo(ix, iy);
      ctx.lineTo(x, y);

      if (currentStep === 1) {
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        ctx.stroke();
        ctx.setLineDash([]);
      } else if (currentStep === 2) {
        drawArrow(ctx, ix, iy, x, y, '#ff0000', 2, true);
      }
    });
  };

  const handleMouseUp = (e) => {
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const newLine = [ix, iy, x, y];
    setLines([...lines, newLine]);
    setDrawing(false);

    const ctx = canvasRef.current.getContext('2d');

    if (currentStep === 1) {
      ctx.beginPath();
      ctx.moveTo(ix, iy);
      ctx.lineTo(x, y);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
      setCurrentStep(2);
    } else if (currentStep === 2) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 4, false);
      setCurrentStep(3);
    }
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width, isPreview = false) => {
    const headLength = isPreview ? 15 : 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    if (isPreview) ctx.setLineDash([5, 5]);
    ctx.stroke();
    if (isPreview) ctx.setLineDash([]);

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const redrawAll = () => {
    if (!canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');
    ctx.clearRect(0, 0, FIXED_WIDTH, FIXED_HEIGHT);

    // Vẽ axis
    if (lines[0]) {
      const [x1, y1, x2, y2] = lines[0];
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
    }

    // Vẽ coord
    if (lines[1]) {
      const [x1, y1, x2, y2] = lines[1];
      drawArrow(ctx, x1, y1, x2, y2, '#ff0000', 4, false);
    }

    // Vẽ polygon
    if (polyPoints.length > 0) {
      ctx.strokeStyle = '#ff4444';
      ctx.lineWidth = 2;
      ctx.fillStyle = 'rgba(255, 68, 68, 0.1)';

      ctx.beginPath();
      ctx.moveTo(polyPoints[0].x, polyPoints[0].y);

      for (let i = 1; i < polyPoints.length; i++) {
        ctx.lineTo(polyPoints[i].x, polyPoints[i].y);
      }

      if (polyPoints.length === 4) {
        ctx.lineTo(polyPoints[0].x, polyPoints[0].y);
        ctx.stroke();
        ctx.fill();
      } else {
        ctx.stroke();
      }

      polyPoints.forEach((point, index) => {
        ctx.beginPath();
        ctx.arc(point.x, point.y, 6, 0, 2 * Math.PI);
        ctx.fillStyle = '#ff4444';
        ctx.fill();
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();

        ctx.fillStyle = 'white';
        ctx.font = 'bold 14px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(index + 1, point.x, point.y);
      });
    }
  };

  const handleComplete = () => {
    setShowPreview(true);
    const output = generateOutput();
    console.log("Kết quả config:", output);
  };

  const handleSave = () => {
    const output = generateOutput();
    onSave(output.list_camera[0].config);
  };

  const handleReset = () => {
    setLines([]);
    setPolyPoints([]);
    setCurrentStep(1);
    setDrawing(false);
    setShowPreview(false);
    redrawAll();
  };

  useEffect(() => {
    if (imageRef.current && cameraData.imagePreview) {
      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = FIXED_WIDTH;
        canvas.height = FIXED_HEIGHT;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
        imageRef.current.src = canvas.toDataURL();

        if (canvasRef.current) {
          canvasRef.current.width = FIXED_WIDTH;
          canvasRef.current.height = FIXED_HEIGHT;
        }
      };
    }
  }, [cameraData.imagePreview]);

  useEffect(() => {
    redrawAll();
  }, [lines, polyPoints]);

  const output = generateOutput();
  const stepStatus = getStepStatus();

  return (
    <div className="drawing-canvas">
      {/* Steps */}
      <div className="steps-container">
        <div className={`step ${currentStep === 1 ? 'active' : ''} ${lines.length >= 1 ? 'completed' : ''}`}>
          <div className="step-number">1</div>
          <div className="step-content">
            <div className="step-title">Vẽ Axis</div>
            <div className="step-status">
              {lines.length >= 1 ? '✅ Hoàn thành' : '⏳ Chưa vẽ'}
            </div>
          </div>
        </div>

        <div className={`step ${currentStep === 2 ? 'active' : ''} ${lines.length >= 2 ? 'completed' : ''}`}>
          <div className="step-number">2</div>
          <div className="step-content">
            <div className="step-title">Vẽ Coord</div>
            <div className="step-status">
              {lines.length >= 2 ? '✅ Hoàn thành' : '⏳ Chưa vẽ'}
            </div>
          </div>
        </div>

        <div className={`step ${currentStep === 3 ? 'active' : ''} ${polyPoints.length >= 4 ? 'completed' : ''}`}>
          <div className="step-number">3</div>
          <div className="step-content">
            <div className="step-title">Vẽ Polygon</div>
            <div className="step-status">
              {polyPoints.length >= 4 ? '✅ Hoàn thành' : `⏳ ${polyPoints.length}/4 điểm`}
            </div>
          </div>
        </div>
      </div>

      {/* Canvas */}
      <div className="canvas-wrapper">
        <div className="canvas-container">
          <img ref={imageRef} alt="Camera" />
          <canvas ref={canvasRef} />
        </div>
      </div>

      {/* Nút hoàn thành */}
      <button 
        className="btn-complete"
        onClick={handleComplete}
        disabled={!lines.length >= 1 || !lines.length >= 2 || polyPoints.length < 4}
      >
        {lines.length >= 1 && lines.length >= 2 && polyPoints.length >= 4 
          ? '✨ Hoàn thành config' 
          : 'Vẽ đủ 3 bước để hoàn thành'}
      </button>

      {/* Preview theo format */}
      {showPreview && (
        <div className="preview-section">
          <h4>📋 Kết quả config:</h4>

          <div className="config-status">
            <h5>Trạng thái các bước:</h5>
            <div className="status-grid">
              <div className="status-row">
                <span>Bước 1 (Axis):</span>
                <span className={lines.length >= 1 ? 'success' : 'pending'}>
                  {lines.length >= 1 ? 'Đã config' : '0'}
                </span>
              </div>
              <div className="status-row">
                <span>Bước 2 (Coord):</span>
                <span className={lines.length >= 2 ? 'success' : 'pending'}>
                  {lines.length >= 2 ? 'Đã config' : '0'}
                </span>
              </div>
              <div className="status-row">
                <span>Bước 3 (Polygon):</span>
                <span className={polyPoints.length >= 4 ? 'success' : 'pending'}>
                  {polyPoints.length >= 4 ? 'Đã config' : `0 (${polyPoints.length}/4)`}
                </span>
              </div>
            </div>
          </div>

          <pre className="json-preview">
            {JSON.stringify(output, null, 2)}
          </pre>

          <div className="coord-summary">
            <h5>Tọa độ đã config:</h5>
            <div className="coord-item">
              <span className="coord-label">Axis:</span>
              <code>[{output.list_camera[0].config.zone[0].axis.join(', ')}]</code>
            </div>
            <div className="coord-item">
              <span className="coord-label">Coord:</span>
              <code>[{output.list_camera[0].config.zone[0].coord.join(', ')}]</code>
            </div>
          </div>

          <div className="preview-actions">
            <button className="btn-copy" onClick={() => {
              navigator.clipboard.writeText(JSON.stringify(output, null, 2));
              alert('Đã copy JSON!');
            }}>
              📋 Copy JSON
            </button>
            <button className="btn-save" onClick={handleSave}>
              💾 Lưu camera
            </button>
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="actions">
        <button className="btn-back" onClick={onBack}>← Quay lại</button>
        <button className="btn-reset" onClick={handleReset}>⟲ Vẽ lại</button>
